inline const HFC *GetHFC(const void *buf) {
  return ::flatbuffers::GetRoot<HFC>(buf);
}

inline const HFC *GetSizePrefixedHFC(const void *buf) {
  return ::flatbuffers::GetSizePrefixedRoot<HFC>(buf);
}

inline const char *HFCIdentifier() {
  return "$HFC";
}

inline bool HFCBufferHasIdentifier(const void *buf) {
  return ::flatbuffers::BufferHasIdentifier(
      buf, HFCIdentifier());
}

inline bool SizePrefixedHFCBufferHasIdentifier(const void *buf) {
  return ::flatbuffers::BufferHasIdentifier(
      buf, HFCIdentifier(), true);
}

template <bool B = false>
inline bool VerifyHFCBuffer(
    ::flatbuffers::VerifierTemplate<B> &verifier) {
  return verifier.template VerifyBuffer<HFC>(HFCIdentifier());
}

template <bool B = false>
inline bool VerifySizePrefixedHFCBuffer(
    ::flatbuffers::VerifierTemplate<B> &verifier) {
  return verifier.template VerifySizePrefixedBuffer<HFC>(HFCIdentifier());
}

inline void FinishHFCBuffer(
    ::flatbuffers::FlatBufferBuilder &fbb,
    ::flatbuffers::Offset<HFC> root) {
  fbb.Finish(root, HFCIdentifier());
}

inline void FinishSizePrefixedHFCBuffer(
    ::flatbuffers::FlatBufferBuilder &fbb,
    ::flatbuffers::Offset<HFC> root) {
  fbb.FinishSizePrefixed(root, HFCIdentifier());
}

